import { readDocBody } from "@/lib/docs-content";
import { problemResponse } from "@/lib/problem";
import { checkRateLimit, rateLimitHeaders } from "@/lib/rate-limit";
import { source } from "@/lib/source";

// Batch Markdown fetch — one POST returns up to MAX_PATHS documentation pages
// as Markdown, saving agents a round-trip per page. Read-only, same content as
// GET /api/md/<slug>. Documented in /api/openapi as `batchGetMarkdown`.
export const dynamic = "force-dynamic";

const MAX_PATHS = 20;

type BatchResult =
	| { path: string; ok: true; title: string; markdown: string }
	| { path: string; ok: false; status: number; detail: string };

function toSlugs(path: string): string[] {
	return path
		.replace(/^\/+|\/+$/g, "")
		.replace(/\.md$/, "")
		.split("/")
		.filter(Boolean);
}

export async function POST(req: Request) {
	const rate = checkRateLimit(req, "md-batch");
	if (rate.limited) {
		return problemResponse(
			{
				title: "Too many requests",
				status: 429,
				detail: `Rate limit exceeded; retry after ${rate.resetSeconds}s.`,
			},
			{ ...rateLimitHeaders(rate), "Retry-After": String(rate.resetSeconds) },
		);
	}

	let paths: unknown;
	try {
		({ paths } = (await req.json()) as { paths?: unknown });
	} catch {
		return problemResponse(
			{
				title: "Invalid request body",
				status: 400,
				detail: 'Expected a JSON body of the form { "paths": ["/docs/...", ...] }.',
			},
			rateLimitHeaders(rate),
		);
	}

	if (!Array.isArray(paths) || paths.length === 0 || !paths.every((p) => typeof p === "string")) {
		return problemResponse(
			{
				title: "Invalid paths",
				status: 400,
				detail: "`paths` must be a non-empty array of doc URL paths (strings).",
			},
			rateLimitHeaders(rate),
		);
	}
	if (paths.length > MAX_PATHS) {
		return problemResponse(
			{
				title: "Too many paths",
				status: 400,
				detail: `At most ${MAX_PATHS} paths per batch request.`,
			},
			rateLimitHeaders(rate),
		);
	}

	const results: BatchResult[] = await Promise.all(
		paths.map(async (path): Promise<BatchResult> => {
			const slugs = toSlugs(path);
			// Doc URLs are /docs/<slugs>; accept paths with or without the prefix.
			const page = source.getPage(slugs[0] === "docs" ? slugs.slice(1) : slugs);
			if (!page) {
				return { path, ok: false, status: 404, detail: "No documentation page at this path." };
			}
			const body = await readDocBody(page.slugs);
			const markdown = `# ${page.data.title}\n\n${page.data.description ?? ""}\n\n${body ?? ""}\n`;
			return { path, ok: true, title: page.data.title, markdown };
		}),
	);

	const idempotencyKey = req.headers.get("idempotency-key");
	return Response.json(
		{ results },
		{
			headers: {
				...rateLimitHeaders(rate),
				"Cache-Control": "public, max-age=300",
				// Batch reads are naturally idempotent; echo the key so clients can
				// correlate retries.
				...(idempotencyKey ? { "Idempotency-Key": idempotencyKey } : {}),
			},
		},
	);
}

export function OPTIONS() {
	return new Response(null, { status: 204 });
}
